// OPENLOGI /items?stock=1 のレスポンスを BQ 行に整形
// 想定レスポンス: { items: [{ id, code, name, stock: { quantity, available, ... } }], pagination: {...} }
// HTTP node pagination で複数 page まとめて入力されるので flatten

const now = new Date().toISOString();
const todayJST = new Date(Date.now() + 9*60*60*1000).toISOString().split('T')[0];
const rows = [];

for (const input of $input.all()) {
  const body = input.json || {};
  const items = Array.isArray(body.items) ? body.items : (Array.isArray(body) ? body : []);
  for (const it of items) {
    const stock = it.stock || {};
    rows.push({
      snapshot_date: todayJST,
      item_id:       String(it.id || ''),
      sku:           it.code || null,
      item_name:     it.name || null,
      quantity:      stock.quantity      != null ? Number(stock.quantity)      : null,
      available:     stock.available     != null ? Number(stock.available)     : null,
      shipping:      stock.shipping      != null ? Number(stock.shipping)      : null,
      requesting:    stock.requesting    != null ? Number(stock.requesting)    : null,
      processing:    stock.processing    != null ? Number(stock.processing)    : null,
      reserved:      stock.reserved      != null ? Number(stock.reserved)      : null,
      backordered:   stock.backordered   != null ? Number(stock.backordered)   : null,
      unallocatable: stock.unallocatable != null ? Number(stock.unallocatable) : null,
      raw_payload:   JSON.stringify(it),
      inserted_at:   now
    });
  }
}

return rows.map(json => ({ json }));
